request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?bbSpec ?bbName ?contPkg ?contPkgName WHERE {
  ?bbSpec vocab:NamedElement_name ?bbName .
  FILTER(
    CONTAINS(LCASE(STR(?bbName)), LCASE("black box specification")) ||
    CONTAINS(LCASE(STR(?bbName)), LCASE("APS black box specification"))
  )

  OPTIONAL { ?bbSpec vocab:PackageableElement_owningPackage ?contPkg . }
  OPTIONAL { ?bbSpec vocab:Element_owner ?contPkg . }
  ?contPkg rdf:type vocab:package .
  ?contPkg vocab:NamedElement_name ?contPkgName .
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pkg ?pkgName ?parentPkg ?parentName WHERE {
  ?pkg rdf:type vocab:package ;
       vocab:NamedElement_name ?pkgName .
  FILTER(
    CONTAINS(LCASE(STR(?pkgName)), LCASE("black%20box%20specification")) ||
    CONTAINS(LCASE(STR(?pkgName)), LCASE("aps%20black%20box%20specification")) ||
    CONTAINS(LCASE(STR(?pkgName)), LCASE("black box specification"))
  )
  OPTIONAL {
    ?parentPkg rdf:type vocab:package .
    ?parentPkg vocab:Package_packagedElement ?pkg .
    OPTIONAL { ?parentPkg vocab:NamedElement_name ?parentName . }
  }
}
LIMIT 25
